	self:ModelNetMsgRecv(LProtoIds.VideoInfoResp,function (...) self:OnVideoInfoResp(...) end)
	self:ModelNetMsgRecv(LProtoIds.VideoInfo2Resp,function (...) self:OnVideoInfo2Resp(...) end)
