	self:ModelNetMsgRecv(LProtoIds.VideoPlayerInfoResp,function (...) self:OnVideoPlayerInfoResp(...) end)
	self:ModelEventRecv(EventNames.ON_WND_CLOSE,function (wndName)
		if wndName == "UIVdoCenter" then
			self:ClearServerInfo()
		end
	end)

	self:ModelEventRecv(EventNames.ON_TIME_ZERO,function ()
		self:OnVideoPlayerInfoReq()
	end)

	--likeRef 表中的类型
	self._likeRefId = 3001
end

