function ModelVideoCenter:OnVideoInfoReq(opera, refId, startIndex, endIndex)
	local pb = LProtoHelper.CreateProto(LProtoIds.VideoInfoReq)
	pb.opera = opera
	pb.refId = refId or 0

	--例如（开始0，结束1 = 只取第1 位数据）
	--（开始0，结束2 = 取第1，第2 位数据）
	--（开始1，结束2 = 只取第2 位数据） 依次类推

	--开始，默认从0位开始，
	pb.startIndex = startIndex or 0

	--结束，默认取最大位
	if not endIndex then
		endIndex = self:GetVideoMaxNum(opera, refId)
	end
	pb.endIndex   = endIndex
	SendMessage(pb,LProtoIds.VideoInfoReq)
end

--查看单个录像
function ModelVideoCenter:OnVideoInfo2Req(videoIndex)
	local pb = LProtoHelper.CreateProto(LProtoIds.VideoInfo2Req)
	pb.videoIndex.id = videoIndex.id
	pb.videoIndex.serverId = tonumber(videoIndex.serverId)
	SendMessage(pb,LProtoIds.VideoInfo2Req)
end

--改变录像相关数据
function ModelVideoCenter:OnVideoOperaReq(opera, videoIndex)
	local pb = LProtoHelper.CreateProto(LProtoIds.VideoOperaReq)
	--1=分享 2=回放 3=点赞 4=收藏录像
	pb.opera = opera
	pb.videoIndex.id = videoIndex.id
	pb.videoIndex.serverId = videoIndex.serverId

	SendMessage(pb,LProtoIds.VideoOperaReq)
end

