	SendMessage(pb,LProtoIds.VideoPlayerInfoReq)
end

--用于数数科技打点，便于获取中文
function ModelVideoCenter:OnVideoTAClientEventReq(stepName, reportId, tabIndex, typeRefId, chatTab)
	local tabName = nil
	if tabIndex then
		tabName = self._TAClientTab[tabIndex]
	end

	local typeName = nil
	if tabIndex and tabIndex == 1 and typeRefId then
		typeName = self._TAClientType[typeRefId]
	end

	if chatTab then
		tabName = self._TAClientChatTab[chatTab]
	end

	gLxTKData:OnTAClientEventReq(LxTKData.CLIENT_REPLAY,stepName,reportId, tabName, typeName)
end
