function ModelVideoCenter:OnVideoInfoResp(pb)
	local isChangeList = false
	local opera = pb.opera
	local refId = pb.refId
	--local startIndex = pb.startIndex
	--local endIndex = pb.endIndex

	if refId == 0 then
		self._serverVideoInfoList[opera] = {}
	else
		if not self._serverVideoInfoList[opera] then
			self._serverVideoInfoList[opera] = {}
		end
		self._serverVideoInfoList[opera][refId] = {}
	end

	for k,v in ipairs(pb.videoInfos) do
		isChangeList = true
		self:AddVideoInfoData(opera, refId, v)
	end

	FireEvent(EventNames.ON_VIDEO_CENTER_INFO_CHANGE, opera, refId)
end

function ModelVideoCenter:AddVideoInfoData(opera, refId, data)
	local videoInfo = StructVideoInfo:New()
	videoInfo:CreateByPb(data)
	videoInfo:SetOpera(opera)
	videoInfo:SetRefId(refId)
	if not self._serverVideoInfoList[opera] then
		self._serverVideoInfoList[opera] = {}
	end

	if opera == ModelVideoCenter.All or opera == ModelVideoCenter.SelfRecord then
		if not self._serverVideoInfoList[opera][refId] then
			self._serverVideoInfoList[opera][refId] = {}
		end
		table.insert(self._serverVideoInfoList[opera][refId], videoInfo)
	else
		table.insert(self._serverVideoInfoList[opera], videoInfo)
	end
end

function ModelVideoCenter:OnVideoInfo2Resp(pb)
	local videoInfo = StructVideoInfo:New()
	videoInfo:CreateByPb(pb.video)
	local combatType = videoInfo:GetCombatType()
	if combatType == LCombatTypeConst.COMBAT_CROSSGRADING_RANK then
		local info = {
			report = videoInfo:GetOtherReport(),
			crossGradingInfo = videoInfo,
			returnCallFunc = function()
				GF.ChangeMap("LCityMap")
				local channel = gModelChat:GetVideoCenterPlayChannel()
				gModelChat:OnClickOpenChat({channel = tonumber(channel)})
			end,
		}
		gModelCrossGrading:OpenRecordDetailsByVideoCenter(info)
	else
		GF.OpenWnd("UIVdoPop",{videoInfo = videoInfo, openEnum =ModelVideoCenter.OpenEnumVideoCenterShare})
	end
end

function ModelVideoCenter:OnVideoOperaResp(pb)
end

function ModelVideoCenter:OnVideoPlayerInfoResp(pb)
	local colVideos = pb.videoPlayer.colVideos or {}
	self._collectVideos = {}
	for k,v in ipairs(colVideos) do
		local id = v.id
		self._collectVideos[id] = true
	end

	local likeVideos = pb.videoPlayer.likeVideos or {}
	self._likeVideos = {}
	for k,v in ipairs(likeVideos) do
		local id = v.id
		self._likeVideos[id] = true
	end

	self._hasLikeNum = pb.videoPlayer.hasLikeNum
	self._videoNum   = pb.videoPlayer.videoNum

	FireEvent(EventNames.ON_VIDEO_CENTER_PLAYER_INFO_CHANGE)
end
