function ModelVideoCenter:GetVideoTypeList()
	local t ={}
	for k,v in pairs(GameTable.MediaTypeRef) do
		table.insert(t, v)
	end

	table.sort(t,function(a,b)
		return a.sort < b.sort
	end)

	return t
end

function ModelVideoCenter:GetVideoTypeRef(refId)
	local cfg = GameTable.MediaTypeRef[refId]
	if not cfg then
		LogError("no find GameTable.MediaTypeRef by refId = "..(refId or "nil"))
	end
	return cfg
end

