function ModelVideoCenter:GetVideoMaxNum(opera, refId)
	if opera == ModelVideoCenter.All then
		return self:GetTypeVideoMax(refId)
	elseif opera == ModelVideoCenter.SelfRecord then
		return self:GetVideoSelfMax()
	elseif opera == ModelVideoCenter.SelfCollect then
		return self:GetVideoCollectMax()
	else
		printInfoNR("opera is not find,  opera = "..(opera or "nil"))
		return 30
	end
end

function ModelVideoCenter:GetVideoFilterTypeRef(refId)
	local cfg = GameTable.MediaFilterTypeRef[refId]
	if not cfg then
		printInfoNR("GameTable.MediaFilterTypeRef[refId] is not find, refId = "..refId)
	end

	return cfg
end

function ModelVideoCenter:GetVideoFilterTypeRefList(filterType)
	local filterTypeList = {}
	for k,v in pairs(GameTable.MediaFilterTypeRef) do
		if v.filterType == filterType then
			table.insert(filterTypeList, v)
		end
	end

	table.sort(filterTypeList, function(a, b)
		return a.sort < b.sort
	end)

	if table.isempty(filterTypeList) then
		printInfoNR("GameTable.MediaFilterTypeRef, cfg is not inf, filterType = "..filterType)
	end

	return filterTypeList
end

function ModelVideoCenter:GetVideoInfoList(opera, refId)
	if opera == ModelVideoCenter.All or opera == ModelVideoCenter.SelfRecord then
		return self._serverVideoInfoList[opera][refId]
	else
		return self._serverVideoInfoList[opera]
	end
end

function ModelVideoCenter:GetFilterVideoInfoList(opera, refId, filterRefId)
	local videoInfoList = self:GetVideoInfoList(opera, refId) or {}
	if not filterRefId or self._filterTypeAll[filterRefId] then
		return videoInfoList
	end

	local filterCfg = self:GetVideoFilterTypeRef(filterRefId)
	local filterType = filterCfg.filterType
	local resList = {}
	if filterType == 1001 then -- 根据右方角色等级筛选
		local filterLvlRange = string.split(filterCfg.value, ',')
		local beginRang		 = tonumber(filterLvlRange[1])
		local endRang		 = tonumber(filterLvlRange[2])
		for k,v in ipairs(videoInfoList) do
			local defensePlayer = v:GetDefensePlayer()
			if defensePlayer then
				local lvl = defensePlayer:GetPlayerLevel()
				if beginRang <= lvl and (lvl <= endRang or endRang <= 0) then
					table.insert(resList ,v)
				end
			end
		end
	elseif filterType == 1002 then -- 根据左方角色左方的胜负情况筛选
		local winType = tonumber(filterCfg.value)
		for k,v in ipairs(videoInfoList) do
			local winner = v:GetWinner()
			if winType == 1 and winner == ModelVideoCenter.AttackPlayer				--左边胜利
					or winType == 0 and winner == ModelVideoCenter.DefensePlayer then 	--左边失败
				table.insert(resList ,v)
			end
		end
	elseif filterType == 1003 then -- 根据赛程划分
		local round = filterRefId % 100300 + 5
		for k,v in ipairs(videoInfoList) do
			if v:GetRound() == round then
				table.insert(resList ,v)
			end
		end
	elseif filterType == 1004 then 						  -- 我的联盟
		local selfGuildId = gModelPlayer:GetGuildId()
		if selfGuildId ~= 0 then
			for k,v in ipairs(videoInfoList) do
				local attackPlayer = v:GetAttackPlayer()
				local attackGuildId
				if attackPlayer then
					attackGuildId = attackPlayer:GetGuildId()
				end
				local defensePlayer = v:GetDefensePlayer()
				local defenseGuildId
				if defensePlayer then
					defenseGuildId = defensePlayer:GetGuildId()
				end

				if selfGuildId == attackGuildId or selfGuildId == defenseGuildId then
					table.insert(resList ,v)
				end
			end
		end
	elseif filterType == 1005 then -- 根据赛程划分
		local round = filterRefId % 100500 + 4
		for k,v in ipairs(videoInfoList) do
			if v:GetRound() == round then
				table.insert(resList ,v)
			end
		end
	elseif filterType == 1006 then -- 根据左方挑战时排位赛名次
		local filterRankRange = string.split(filterCfg.value, ',')
		local beginRank		 = tonumber(filterRankRange[1])
		local endRank		 = tonumber(filterRankRange[2])
		for k,v in ipairs(videoInfoList) do
			local rank = v:GetRank() or 9999
			if beginRank <= rank and (rank <= endRank or endRank <= 0) then
				table.insert(resList ,v)
			end
		end
	elseif filterType == 1010 then
		for k,v in ipairs(videoInfoList) do
			if self:CheckSimuFilter(v,filterRefId) then
				table.insert(resList ,v)
			end
		end
	end

	return resList
end

function ModelVideoCenter:CheckSimuFilter(videoInfo,filterRefId)
	local group = videoInfo.group
	local schedule = videoInfo.schedule
	local round = videoInfo.round
	local filterPara = self._simuFilterPara[filterRefId]

	local isStart = videoInfo:GetStartTime() /1000 < GetTimestamp()

	if not isStart then
		return
	end

	if not filterPara then
		return false
	end

	if filterPara.group == group and filterPara.schedule == schedule and filterPara.roundMap[round] then
		return true
	end

	return false
end

function ModelVideoCenter:GetShareName(playerName1, playerName2)
	return string.replace(ccClientText(21513), playerName1, playerName2)
end

function ModelVideoCenter:GetTitleName(combatType, roundIndex)
	local titleStr = gModelBattle:GetCombatTypeName(combatType)
	local roundName = ""
	if combatType == LCombatTypeConst.COMBAT_ARENA_PEAK_ATTACK then --巅峰赛，没有64强, 将前面1-6轮整合成“选拔赛”
		if roundIndex <= 6 then
			roundName = ccClientText(21531)
		else
			roundName = ccClientText(21516 + roundIndex)
		end
		titleStr = string.replace(ccClientText(21529), titleStr, roundName)
	elseif combatType == LCombatTypeConst.COMBAT_CROSS_SERVER_CHAMPION then --跨界周榜，有64强, 将前面1-6轮整合成“选拔赛”
		if roundIndex <= 6 then
			roundName = ccClientText(21531)
		else
			roundName = ccClientText(21516 + roundIndex - 1)
		end
		titleStr = string.replace(ccClientText(21529), titleStr, roundName)
	end

	return titleStr
end

function ModelVideoCenter:GetHasLikeNum()
	return self._hasLikeNum or 0
end

function ModelVideoCenter:GetHasRewardLikeNum()
	local haveLikeNum = gModelVideoCenter:GetHasLikeNum()
	if haveLikeNum <= 0 then
		return 0
	end

	local timeReward = self:GetLikeTimeReward()
	local time       = self:GetLikeTime()
	local resValue   = timeReward - (time - haveLikeNum)
	return math.max(resValue, 0)
end

function ModelVideoCenter:GetCurCollectNum()
	if table.isempty(self._collectVideos) then
		return 0
	end

	local maxNum = 0
	for k,v in pairs(self._collectVideos) do
		maxNum = maxNum + 1
	end

	return maxNum
end

function ModelVideoCenter:GetLikeRefId()
	return self._likeRefId
end

function ModelVideoCenter:GetLikeTime()
	local likeType = self:GetLikeRefId()
	local time = gModelRank:GetLikeRefTargetKey(likeType, "time")
	if not time then
		return 0
	end

	return time
end

function ModelVideoCenter:GetLikeTimeReward()
	local likeType = self:GetLikeRefId()
	local timeReward = gModelRank:GetLikeRefTargetKey(likeType, "timeReward")
	if not timeReward then
		return 0
	end

	return timeReward
end

function ModelVideoCenter:SetLikeVideoState(id)
	if not self._likeVideos then
		self._likeVideos = {}
	end

	self._likeVideos[id] = true
end

function ModelVideoCenter:SetCollectVideoState(id)
	if not self._collectVideos then
		self._collectVideos = {}
	end

	local oldState = self._collectVideos[id]
	self._collectVideos[id] = not oldState
end

function ModelVideoCenter:CheckVideoTypeIsOpen(refId, needTip)
	local cfg = self:GetVideoTypeRef(refId)
	if not cfg then
		return false
	end

	local lock  = cfg.lock
	local isOpen = true
	if lock and lock ~= 0 then
		needTip = needTip or false
		isOpen = gModelFunctionOpen:CheckIsOpened(lock, needTip)
	end

	return isOpen
end

function ModelVideoCenter:CheckHaveVideoInfo(opera, refId)
	if table.isempty(self._serverVideoInfoList) or table.isempty(self._serverVideoInfoList[opera]) then
		return false
	end

	if opera == ModelVideoCenter.All and table.isempty(self._serverVideoInfoList[opera][refId]) then
		return false
	end

	return true
end

function ModelVideoCenter:CheckIsCollectById(id)
	if table.isempty(self._collectVideos) then
		return false
	end

	return self._collectVideos[id] or false
end

function ModelVideoCenter:CheckIsLikeById(id)
	if table.isempty(self._likeVideos) then
		return false
	end

	return self._likeVideos[id] or false
end

function ModelVideoCenter:CheckHaveLikeNum()
	local haveLikeNum = gModelVideoCenter:GetHasLikeNum()
	return haveLikeNum > 0
end

function ModelVideoCenter:CheckHaveRewardLikeNum()
	local haveLikeNum = gModelVideoCenter:GetHasLikeNum()
	if haveLikeNum <= 0 then
		return false
	end

	local timeReward = self:GetLikeTimeReward()
	local time       = self:GetLikeTime()
	return (time - haveLikeNum) < timeReward
end

function ModelVideoCenter:CheckLikeRed()
	if not self._videoNum or self._videoNum <= 0 then
		return false
	end

	--日服增加消失规则：玩家等级100级后红点消失
	if gLGameLanguage:IsJapanRegion() then
		local lv = gModelPlayer:GetPlayerLv()
		if lv > 100 then
			return false
		end
	end

	return self:CheckHaveRewardLikeNum()
end

function ModelVideoCenter:RemoveCollectVideoInfoData(id)
	local infoList = self._serverVideoInfoList[ModelVideoCenter.SelfCollect]
	local removeKey
	for k,v in ipairs(infoList) do
		if id == v:GetId() then
			removeKey = k
			break
		end
	end

	if not removeKey then
		return false
	end

	table.remove(self._serverVideoInfoList[ModelVideoCenter.SelfCollect], removeKey)
	return true
end

function ModelVideoCenter:GetSimuFilterShow(para)
	local schedule = para.schedule
	local group = para.group
	local round = para.round

	local refId = nil
	for k,v in pairs(self._simuFilterPara) do
		if v.schedule == schedule and v.group == group and v.roundMap[round] then
			refId = k
			break
		end
	end

	if refId then
		local filterCfg = self:GetVideoFilterTypeRef(refId)
		return ccLngText(filterCfg.name)
	end

	return ""
end


return ModelVideoCenter